225→function managedSiteAddress(reportPort: number, exposure: ProjectEntry['report_exposure']): string {
226→  if (exposure === 'lan') {
227→    return `http://:${String(reportPort)}`
228→  }
229→  return `http://127.0.0.1:${String(reportPort)}, http://localhost:${String(reportPort)}`
230→}
231→
232→function quoteForCaddyPath(value: string): string {
233→  const normalized = toPosixPath(resolve(value)).replace(/"/g, '\\"')
234→  return `"${normalized}"`
235→}
236→
237→function writeTextIfChanged(path: string, content: string): void {
238→  if (existsSync(path) && readFileSync(path, 'utf-8') === content) {
239→    return
240→  }
241→  writeFileSync(path, content, 'utf-8')
242→}
243→
244→function validateManagedCaddyConfig(mainConfigPath: string): void {
245→  execCommand('caddy', ['adapt', '--config', mainConfigPath, '--adapter', 'caddyfile', '--validate'], {
246→    allowFailure: false,
247→  })
248→}
249→
250→function reloadManagedCaddy(mainConfigPath: string): void {
251→  execCommand('caddy', ['reload', '--config', mainConfigPath, '--adapter', 'caddyfile'])
252→}
253→
254→function adaptManagedCaddyConfig(mainConfigPath: string): string {
255→  return execCommand('caddy', ['adapt', '--config', mainConfigPath, '--adapter', 'caddyfile'])
256→}
257→
258→async function fetchRunningCaddyConfigText(): Promise<string | null> {
259→  try {
260→    const response = await fetch(`${CADDY_ADMIN_URL}/config/`)
261→    if (!response.ok) return null
262→    return await response.text()
263→  } catch {
264→    return null
265→  }
266→}
267→
268→function stableJsonFromText(text: string | null): string | null {
269→  if (text === null) return null
270→  try {
271→    return JSON.stringify(sortJsonKeys(JSON.parse(text)))
272→  } catch {
273→    return null
274→  }
275→}
276→
277→function sortJsonKeys(value: unknown): unknown {
278→  if (Array.isArray(value)) {
279→    return value.map(item => sortJsonKeys(item))
280→  }
281→  if (value !== null && typeof value === 'object') {
282→    return Object.fromEntries(
283→      Object.keys(value)
284→        .sort((left, right) => left.localeCompare(right))
285→        .map(key => [key, sortJsonKeys((value as Record<string, unknown>)[key])]),
286→    )
287→  }
288→  return value
289→}
290→
291→function localUrlsForProject(reportPort: number): string[] {
292→  return [
293→    `http://127.0.0.1:${String(reportPort)}/`,
294→    `http://localhost:${String(reportPort)}/`,
295→  ]
296→}
297→
298→function lanUrlsForProject(
299→  reportPort: number,
300→  exposure: ProjectEntry['report_exposure'],
301→): string[] {
302→  if (exposure !== 'lan') return []
303→
304→  const urls = new Set<string>()
305→  const interfaces = networkInterfaces()
306→  for (const addresses of Object.values(interfaces)) {
307→    for (const address of addresses ?? []) {
308→      if (address.family !== 'IPv4' || address.internal) continue
309→      urls.add(`http://${address.address}:${String(reportPort)}/`)
310→    }
311→  }
312→  return [...urls].sort((left, right) => left.localeCompare(right))
313→}
314→
315→function formatExecError(error: unknown): string {
316→  if (error instanceof Error && error.message) {
317→    return error.message
318→  }
319→  return String(error)
320→}
